INSERT INTO public.question_banks (id, code, title, content, correct_answer, question_type, difficulty, skill, points, subject_id, exam_level, explanation) VALUES ('411bf065-3159-4779-8ca3-68fbebe0efa0', 'LTS_Q2_2025_FLY_001', 'Kể câu chuyện theo hình', '{"images": ["questions/story-images/images/1773993315211_b70ec8df_q2_fly_speaking_p3_1.png", "questions/story-images/images/1773993321658_9c103aca_q2_fly_speaking_p3_2.png", "questions/story-images/images/1773993326419_63eefd09_q2_fly_speaking_p3_3.png", "questions/story-images/images/1773993332641_6b320a35_q2_fly_speaking_p3_4.png", "questions/story-images/images/1773993339328_50d82d1e_q2_fly_speaking_p3_5.png"], "audioUrl": "listen-and-speak/audio/1773993532303_0e289f90_q2_fly_speaking_p3.mp3", "isBackup": false}', '{"expectedAnswers": ["Sophia''s grandmother gives her two tickets for a pop concert. She''s very excited because she loves pop music and she has never been to a concert before.", "Sophia goes to the concert by car, which is driven by her mother. She can''t hide her excitement on the way there.", "Suddenly, she sees a young woman is looking for a lift. She asks her mother to help that lady.", "Surprisingly, she finds out that that woman is a famous pop star, who is going to perform at the concert that she''s heading to. She''s really happy to know that.", "At the concert, the famous singer publicly thank Sophia for the favor, and sing a song for her in front of the crowd. It is a day to remember for Sophia."]}', 'LISTEN_AND_SPEAK_WITH_STORY_IMAGES', 'medium', null, 1.00, null, null, '');
