INSERT INTO public.questions (id, content, correct_answer, points, question_type, explanation, exam_id, part_id, part_no, question_number, group_id, question_bank_id, question_skill_type, is_example, suggested_answers) VALUES ('69b90de7-8450-4556-92ae-163014418772', '{"images": ["questions/story-images/images/1774252138964_fbfae653_speaking_flyers_3_1.webp", "questions/story-images/images/1774252171550_171310b2_speaking_flyers_3_2.webp", "questions/story-images/images/1774252201650_b52811fa_speaking_flyers_3_3.webp", "questions/story-images/images/1774252228920_6e8e4cf2_speaking_flyers_3_4.webp", "questions/story-images/images/1774252259408_bafa9e89_speaking_flyers_3_5.webp"], "audioUrl": "listen-and-speak/audio/1773993532303_0e289f90_q2_fly_speaking_p3.mp3", "isBackup": false}', '{"expectedAnswers": ["Sophia''s grandmother gives her two tickets for a pop concert. She''s very excited because she loves pop music and she has never been to a concert before.", "Sophia goes to the concert by car, which is driven by her mother. She can''t hide her excitement on the way there.", "Suddenly, she sees a young woman is looking for a lift. She asks her mother to help that lady.", "Surprisingly, she finds out that that woman is a famous pop star, who is going to perform at the concert that she''s heading to. She''s really happy to know that.", "At the concert, the famous singer publicly thank Sophia for the favor, and sing a song for her in front of the crowd. It is a day to remember for Sophia."]}', 1.00, 'LISTEN_AND_SPEAK_WITH_STORY_IMAGES', '', '638b6fe3-d53c-42d4-9e7d-36d9e05c4810', '3', 3, 18, null, '411bf065-3159-4779-8ca3-68fbebe0efa0', 'SPEAKING', false, null);
